#include <stdio.h>
#define MAX_DIGITS 200

void multiply(int *num, int *len, int x){
    int carry=0;
    for(int i=0;i<*len;i++){
        int prod=num[i]*x+carry;
        num[i]=prod%10;
        carry=prod/10;
    }
    while(carry){
        num[(*len)++]=carry%10;
        carry/=10;
    }
}

int main(){
    int T,N;
    if(scanf("%d",&T)!=1) return 0;
    while(T--){
        scanf("%d",&N);
        int res[MAX_DIGITS];
        int len=1; res[0]=1;
        int i=N;
        if(i>0){
            do{
                multiply(res,&len,i);
                i--;
            }while(i>0);
        }
        for(int j=len-1;j>=0;--j) putchar(res[j]+'0');
        putchar('\n');
    }
    return 0;
}

